class Solution:
    def baseNeg2(self, n):
        if n == 0:
            return '0'
        # verify by reconstructing the value from candidate digits
        # build digits greedily then check
        digits = []
        x = n
        while x != 0:
            digits.append(x & 1)
            x = -(x >> 1)
        s = ''.join(str(d) for d in reversed(digits))
        return s

