var baseNeg2 = function(n) {
    if (n === 0) return '0';
    const res = [];
    while (n !== 0) {
        let r = ((n % 2) + 2) % 2;
        res.push(String(r));
        n = (n - r) / -2;
    }
    return res.reverse().join('');
};
